// PizzaList.jsx - Componente de lista
import React, { useState } from 'react';
import PizzaModal from './PizzaModal';
import { Grid, Card, CardImage, CardTitle, CardDesc, Button } from '../styles/styles';

const PizzaList = ({ pizzas }) => {
  // eslint-disable-next-line no-self-compare
  const [selectedPizza, setSelectedPizza] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handlePizzaClick = (pizza) => {
    setSelectedPizza(pizza);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedPizza(null);
  };

  return (
    <div>
      <Grid>
        {pizzas.map((pizza) => (
          <Card key={pizza.id} onClick={() => handlePizzaClick(pizza)}>
            <CardImage src={pizza.image} alt={pizza.name} />
            <CardTitle>{pizza.name}</CardTitle>
            <CardDesc>{pizza.description}</CardDesc>
            <Button>Adicionar ao carrinho</Button>
          </Card>
        ))}
      </Grid>
      {isModalOpen && selectedPizza && (
        <PizzaModal pizza={selectedPizza} onClose={handleCloseModal} />
      )}
    </div>
  );
};

export default PizzaList;
